channels = get_channels()
if len(channels) == 0:
    raise ValueError("No channels found.")

all_users = set()
messages_by_channel = {}

for channel in channels:
    channel_users = get_users_in_channel(channel)
    channel_messages = read_channel_messages(channel)

    all_users = all_users | set(channel_users)
    all_users = all_users | set([message.sender for message in channel_messages])
    messages_by_channel[channel] = channel_messages

if len(all_users) == 0:
    raise ValueError("No users found.")

message_counts = {user: 0 for user in all_users}

for channel in channels:
    for message in messages_by_channel[channel]:
        sender = message.sender
        message_counts[sender] = message_counts.get(sender, 0) + 1

ranked_rows = sorted(
    [(-message_counts.get(user, 0), user.lower(), user) for user in all_users]
)
ranked_users = [row[2] for row in ranked_rows]

for index, user in enumerate(ranked_users):
    rank = index + 1
    send_direct_message(
        user,
        "Congrats on being the {}-th most active user!".format(rank),
    )

print(
    [
        {
            "rank": index + 1,
            "user": user,
            "message_count": message_counts.get(user, 0),
        }
        for index, user in enumerate(ranked_users)
    ]
)
